const email = $input.first().json;
const body = email.text || email.snippet || email.body || '';
const subject = email.subject || email.Subject || '';
const sender = email.from || email.From || email.sender || '';
const threadId = email.threadId || email.id || '';
const gmailId = email.id || email.messageId || '';

return [{
  json: {
    gmailId,
    threadId,
    sender,
    subject,
    body: body.substring(0, 2000)
  }
}];

const response = $input.first().json;
let classification;
try {
  const content = response.content[0].text;
  classification = JSON.parse(content);
} catch(e) {
  classification = {
    category: 'FAQ',
    priority: 'P2',
    language: 'HR',
    summary: 'Could not parse classification',
    requires_human: true,
    suggested_action: 'Manual review needed',
    auto_reply: ''
  };
}

const emailData = $('Extract Email Fields').first().json;

const webhookMap = {
  MEDICAL: $vars.SLACK_WEBHOOK_MEDICAL,
  ORDER: $vars.SLACK_WEBHOOK_ORDER,
  BUSINESS: $vars.SLACK_WEBHOOK_BUSINESS,
  FAQ: $vars.SLACK_WEBHOOK_FAQ,
  URGENT: $vars.SLACK_WEBHOOK_URGENT
};

const priorityEmoji = { P1: '🚨', P2: '⚠️', P3: 'ℹ️' };
const emoji = priorityEmoji[classification.priority] || 'ℹ️';
const urgentPrefix = classification.priority === 'P1' ? '🚨 *HITNO / URGENT* 🚨\n' : '';

const slackWebhook = webhookMap[classification.category] || webhookMap['FAQ'];
const gmailLink = 'https://mail.google.com/mail/u/0/#inbox/' + emailData.threadId;
const slackMessage = urgentPrefix + emoji + ' *Nova poruka — ' + classification.category + '* (' + classification.priority + ')\n*Od:* ' + emailData.sender + '\n*Predmet:* ' + emailData.subject + '\n*Sažetak:* ' + classification.summary + '\n*Akcija:* ' + classification.suggested_action + '\n*Auto-odgovor:* ' + (classification.requires_human ? 'Ne — čeka odgovor' : 'Da') + '\n<' + gmailLink + '|📧 Otvori i odgovori u Gmailu>';

const canAutoReply = !classification.requires_human && !!classification.auto_reply;

return [{ json: { 
  ...emailData, 
  ...classification,
  slackWebhook,
  urgentWebhook: $vars.SLACK_WEBHOOK_URGENT,
  slackMessage,
  autoReply: classification.auto_reply || '',
  isP1: classification.priority === 'P1',
  canAutoReply
} }];

